const arr = [1, 2, 3];

// push lives on Array.prototype, not on arr directly
console.log(arr.hasOwnProperty("push"));           // false — not on arr
console.log(Array.prototype.hasOwnProperty("push"));// true — on prototype

// The chain:
console.log(Object.getPrototypeOf(arr) === Array.prototype); // true
console.log(typeof Array.prototype.push); // function

function Animal(name) {
  this.name = name; // own property
}
Animal.prototype.speak = function() {
  return `${this.name} makes a sound.`;
};

const dog = new Animal("Rex");

console.log(dog.hasOwnProperty("name"));   // true — own
console.log(dog.hasOwnProperty("speak"));  // false — on prototype
console.log(dog.speak());                  // found on prototype
console.log(Object.getPrototypeOf(dog) === Animal.prototype);

// Class syntax:
class PersonClass {
  constructor(name) { this.name = name; }
  greet() { return `Hello from ${this.name}`; }
}

// Equivalent prototype code:
function PersonProto(name) { this.name = name; }
PersonProto.prototype.greet = function() { return `Hello from ${this.name}`; };

const p1 = new PersonClass("Alice");
const p2 = new PersonProto("Bob");

console.log(p1.greet());
console.log(p2.greet());
console.log(typeof PersonClass);  // function!
console.log(typeof PersonProto);  // function

const animal = {
  speak() { return `${this.name} speaks.`; },
  eat()   { return `${this.name} eats.`; }
};

const dog = Object.create(animal);
dog.name = "Rex";
dog.bark = function() { return `${this.name} barks!`; };

console.log(dog.speak());  // from prototype
console.log(dog.eat());   // from prototype
console.log(dog.bark());  // own method
console.log(Object.getPrototypeOf(dog) === animal);

function Animal(name) {
  this.name = name;
}
Animal.prototype.speak = function() {};
Animal.prototype.type = "animal";

const dog = new Animal("Rex");
dog.breed = "Labrador";

// hasOwnProperty — only own:
console.log(dog.hasOwnProperty("name"));  // true
console.log(dog.hasOwnProperty("speak")); // false — on prototype

// in — includes prototype:
console.log("speak" in dog);  // true
console.log("type"  in dog);  // true

// for...in includes inherited — filter with hasOwnProperty:
for (const key in dog) {
  if (dog.hasOwnProperty(key)) console.log(`Own: ${key}`);
}

// DO NOT do this in real code — demo only!
Array.prototype.sum = function() {
  return this.reduce((a, b) => a + b, 0);
};

console.log([1, 2, 3, 4, 5].sum()); // works

// The danger: for...in now leaks!
const arr = [1, 2, 3];
for (const key in arr) {
  console.log(key); // 0, 1, 2, and 'sum'! — polluted
}

const original = { name: "Alex", address: { city: "London" } };

// Shallow copy:
const copy = { ...original };
copy.name = "Bob";  // safe — primitive
copy.address.city = "Paris";  // DANGER — mutates original!

console.log(original.name);         // Alex — safe
console.log(original.address.city); // Paris! — mutated!

// Deep copy using structuredClone (modern):
const deepCopy = structuredClone(original);
deepCopy.address.city = "Tokyo";
console.log(original.address.city); // still Paris — safe
